export function getCityData(slug: string): CityData | undefined {
  const meta = cityMeta[slug];
  if (!meta) return undefined;
  return {
    ...meta,
    courses: getCoursesByCity(slug),
    publicCourses: getPublicCourses(slug),
    privateCourses: getPrivateCourses(slug),
    resortCourses: getResortCourses(slug),
  };
}

export function getAllCities(): { city: string; state: string; slug: string }[] {
  return Object.values(cityMeta).map(c => ({ city: c.city, state: c.state, slug: c.slug }));
}

export { cityMeta };
